import{_ as i,o as e,c as r,a2 as l}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"融资利息","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"margin/interest-rules.md","filePath":"zh-CN/margin/interest-rules.md"}'),t={name:"margin/interest-rules.md"};function o(n,a,h,s,d,p){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="融资利息" tabindex="-1">融资利息 <a class="header-anchor" href="#融资利息" aria-label="Permalink to &quot;融资利息&quot;">​</a></h1><p>融资利息的计算公式、计息时机、利率参考及节假日处理规则。</p><h2 id="融资利息计算公式" tabindex="-1">融资利息计算公式 <a class="header-anchor" href="#融资利息计算公式" aria-label="Permalink to &quot;融资利息计算公式&quot;">​</a></h2><p>融资利息以交收结算后的账户实际金额进行计息。</p><p><strong>长桥香港：</strong><br> 当日融资利息 = 当日交易日闭市后融资余额 × 融资利率 / 365</p><p><strong>长桥新加坡：</strong><br> 当日融资利息 = 交易日 18:00 SGT 的融资余额 × 年融资利率 / 365</p><p>最低 0.01 单个币种，如果不足 0.01 单个币种则不计息。融资天数以 365 天为一年，按自然日计算。</p><h2 id="融券利息计算公式" tabindex="-1">融券利息计算公式 <a class="header-anchor" href="#融券利息计算公式" aria-label="Permalink to &quot;融券利息计算公式&quot;">​</a></h2><p>HK/SG 通用：</p><p>每日已交收卖空股票数量 × 【(收盘价 × 102%) 向上取整】 × 卖空参考利率 / 360</p><h2 id="当前融资利率" tabindex="-1">当前融资利率 <a class="header-anchor" href="#当前融资利率" aria-label="Permalink to &quot;当前融资利率&quot;">​</a></h2><p>长桥香港融资利率请以 App 或官网最新公示为准。</p><p>长桥新加坡融资利率请以 App 或官网最新公示为准。</p><p>注：融资利率可能在不预先通知的情况下进行周期性调整，以适应货币汇率的变化。</p><h2 id="计息起始时间" tabindex="-1">计息起始时间 <a class="header-anchor" href="#计息起始时间" aria-label="Permalink to &quot;计息起始时间&quot;">​</a></h2><p>使用融资购买股票即产生现金欠款，账户实际产生欠款的时间在清算完成当天开始计算。</p><ul><li>港股清算时间为 T+2，即 T+2 当天开始计息</li><li>美股清算时间为 T+1，即 T+1 当天开始计息</li></ul><p>日计月结。</p><h2 id="清算时间点" tabindex="-1">清算时间点 <a class="header-anchor" href="#清算时间点" aria-label="Permalink to &quot;清算时间点&quot;">​</a></h2><ul><li>长桥香港：美/港股清算时间点为每交易日 17:00（香港时间）</li><li>长桥新加坡：新加坡/美国/香港股票的结算时间为每个交易日 18:00（新加坡时间）</li></ul><h2 id="不计息情况" tabindex="-1">不计息情况 <a class="header-anchor" href="#不计息情况" aria-label="Permalink to &quot;不计息情况&quot;">​</a></h2><p>使用融资后以下两种情况不计息：</p><ol><li>当天融资买入后，当天卖出，且卖出获得金额高于买入花费金额</li><li>在结算当天清算时间点（HK 17:00 / SG 18:00）前入金或换汇，则不计算利息</li></ol><p>示例（香港）：</p><ul><li>例一：客户于 1 月 1 日（香港时间）使用融资购买了港股，账务日期为 1 月 1 日。客户于 1 月 3 日 17:00（香港时间）之前存入该笔交易款项（连同相关交易费用），将不会产生融资利息。</li><li>例二：客户于 1 月 1 日（香港时间）使用融资购买了美股，账务日期为 1 月 2 日。客户于 1 月 3 日 17:00（香港时间）之前存入该笔交易款项（连同相关交易费用），将不会产生融资利息。</li></ul><h2 id="偿还融资欠款的方式" tabindex="-1">偿还融资欠款的方式 <a class="header-anchor" href="#偿还融资欠款的方式" aria-label="Permalink to &quot;偿还融资欠款的方式&quot;">​</a></h2><p>目前偿还融资欠款一般有三种方式：</p><ol><li>货币兑换：其他货币有余额足够偿还融资欠款，可使用货币兑换功能兑换成相应币种用于补足欠款</li><li>入金：客户入金后会优先补足欠款，补足欠款的部分在入金到账后将不再计息</li><li>卖出股票：卖出股票后需等待清算完成。港股 T+2、美股 T+1 清算，在卖出后的等待期内账户依然有欠款并产生融资利息</li></ol><h2 id="调整融资额度" tabindex="-1">调整融资额度 <a class="header-anchor" href="#调整融资额度" aria-label="Permalink to &quot;调整融资额度&quot;">​</a></h2><p>融资额度支持按需在 App 内提高或降低，每 24 小时内最多申请 2 次（新加坡账户每 24 小时限 1 次）。详细操作参见<a href="/wiki/margin/credit-limit">融资额度</a>。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/margin/credit-limit">融资额度</a> — 额度评估、降低与关闭操作</li><li><a href="/wiki/margin/margin-requirements">保证金</a> — 保证金结构与追缴（Margin Call）机制</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/getting-started/first-margin-buy">完成首笔融资买入</a></li><li><a href="/wiki/margin/credit-limit">融资额度</a></li><li><a href="/wiki/margin/faq">融资常见问题</a></li><li><a href="/wiki/margin">融资融券</a></li></ul>',34)])])}const m=i(t,[["render",o]]);export{c as __pageData,m as default};
